// Modal.js
import React from "react";
import "../styles/Modal.css"; // Importing the CSS for the modal

const Modal = ({ selectedProfessional, closeModal }) => {
    return (
        <div className="modal-overlay" onClick={closeModal}>
            <div className="modal-content" onClick={(e) => e.stopPropagation()}>
                <div className="modal-left">
                    <img src={selectedProfessional.img} alt={selectedProfessional.name} />
                </div>
                <div className="modal-right">
                    <h3>{selectedProfessional.name}</h3>
                    <div className="professional-icon">
                        <img src="./images/mail.jpg" alt="Icon" />
                    </div>
                    <div className="professional-email">
                        {selectedProfessional.email}
                    </div>
                    <div className="professional-role">{selectedProfessional.role}</div>
                    <div className="professional-background">
                        <h4>Professional Background</h4>
                        <p>{selectedProfessional.background}</p>
                    </div>
                    <div className="professional-experience">
                        <h4>Experience</h4>
                        <p>{selectedProfessional.experience}</p>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default Modal;
